import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.DLWhSH9p.js";const m=JSON.parse('{"title":"Roles","description":"","frontmatter":{},"headers":[],"relativePath":"guide/auth.md","filePath":"guide/auth.md"}'),l={name:"guide/auth.md"};function i(s,e,n,d,u,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h1><p>Every user in CRAFT Studio belongs to one of four roles. Your role decides which channels you see, which AI models you can run, and which premium features are unlocked.</p><h2 id="the-four-roles" tabindex="-1">The four roles <a class="header-anchor" href="#the-four-roles" aria-label="Permalink to &quot;The four roles&quot;">​</a></h2><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><ul><li>Full access to all channels regardless of ownership</li><li>All AI models available (Claude Opus, Sonnet, Haiku, Gemini, Ollama)</li><li>Can manage all users&#39; resources and content</li><li>Automatically qualifies as premium</li></ul><h3 id="editor" tabindex="-1">Editor <a class="header-anchor" href="#editor" aria-label="Permalink to &quot;Editor&quot;">​</a></h3><ul><li>Read access to all channels</li><li>Write access only to channels they own</li><li>Standard model access (upgraded with their own API keys, or to premium via the premium role)</li></ul><h3 id="premium" tabindex="-1">Premium <a class="header-anchor" href="#premium" aria-label="Permalink to &quot;Premium&quot;">​</a></h3><ul><li>All advanced Claude models: Opus, Sonnet, Haiku</li><li>Proposals and Jobs features unlocked (channel-scoped)</li><li>Full Claude Agent SDK capabilities including MCP tool integrations</li></ul><h3 id="standard" tabindex="-1">Standard <a class="header-anchor" href="#standard" aria-label="Permalink to &quot;Standard&quot;">​</a></h3><ul><li>Own channels only (create, read, update, delete)</li><li>Limited to Ollama local models and Claude Haiku</li><li>No proposals or jobs access</li><li>All other content-creation features</li></ul><h2 id="three-tier-model-access" tabindex="-1">Three-tier model access <a class="header-anchor" href="#three-tier-model-access" aria-label="Permalink to &quot;Three-tier model access&quot;">​</a></h2><p>Model availability depends on your role <strong>and</strong> which API keys you&#39;ve saved in your profile:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Who qualifies</th><th>Available models</th></tr></thead><tbody><tr><td><strong>Standard</strong></td><td>All authenticated users</td><td>Ollama (local) + Claude Haiku</td></tr><tr><td><strong>API keys</strong></td><td>Users with saved Gemini / Claude keys</td><td>+ Gemini models</td></tr><tr><td><strong>Premium</strong></td><td><code>premium</code> or <code>admin</code> role</td><td>All Claude models (Opus, Sonnet, Haiku) + Gemini + Ollama + MCP tools</td></tr></tbody></table><p>API keys are stored per-user (encrypted in the database) and managed from the avatar menu → <strong>API Keys</strong>. The studio checks your keys first, then falls back to the server-wide defaults.</p><h2 id="change-password" tabindex="-1">Change password <a class="header-anchor" href="#change-password" aria-label="Permalink to &quot;Change password&quot;">​</a></h2><ol><li>Click your <strong>avatar</strong> in the top-right of the top chrome.</li><li>Click <strong>Change password</strong> in the dropdown.</li><li>Enter your <strong>current password</strong> for verification.</li><li>Enter and confirm your <strong>new password</strong>.</li></ol><p>The current-password check prevents unauthorised changes if a session is left open.</p><h2 id="sign-out" tabindex="-1">Sign out <a class="header-anchor" href="#sign-out" aria-label="Permalink to &quot;Sign out&quot;">​</a></h2><p>Click your avatar → <strong>Sign out</strong> at the bottom of the dropdown. This ends your session and returns you to the login screen.</p>',20)])])}const p=a(l,[["render",i]]);export{m as __pageData,p as default};
